previewCss:
.darma-loader-loading-io-28 {
      display: inline-grid;
      grid-template-columns: repeat(3, 11px);
      gap: 5px;
    }
    .darma-loader-loading-io-28 i {
      width: 11px;
      height: 11px;
      border-radius: 4px;
      background: var(--loader-color);
      animation: darma-loader-loading-io-28-gridFlash 1.15s ease-in-out infinite;
    }
    .darma-loader-loading-io-28 i:nth-child(1) { animation-delay: 0.00s; }
.darma-loader-loading-io-28 i:nth-child(2) { animation-delay: 0.08s; }
.darma-loader-loading-io-28 i:nth-child(3) { animation-delay: 0.16s; }
.darma-loader-loading-io-28 i:nth-child(4) { animation-delay: 0.08s; }
.darma-loader-loading-io-28 i:nth-child(5) { animation-delay: 0.16s; }
.darma-loader-loading-io-28 i:nth-child(6) { animation-delay: 0.24s; }
.darma-loader-loading-io-28 i:nth-child(7) { animation-delay: 0.16s; }
.darma-loader-loading-io-28 i:nth-child(8) { animation-delay: 0.24s; }
.darma-loader-loading-io-28 i:nth-child(9) { animation-delay: 0.32s; }
    @keyframes darma-loader-loading-io-28-gridFlash { 0%, 70%, 100% { opacity: .25; transform: scale(.75); } 35% { opacity: 1; transform: scale(1); } }

